<?php

declare(strict_types=1);

namespace Modright\Tests;

use Modright\Database;
use Modright\UserDeletionService;
use Modright\UserService;
use PDO;
use PHPUnit\Framework\TestCase;

final class UserDeletionServiceTest extends TestCase
{
    private function database(): PDO{$db=new PDO('sqlite::memory:');$db->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$db->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);$db->exec('PRAGMA foreign_keys=ON');Database::migrate($db);return$db;}
    public function testDeletionRequiresOwnershipTransfer(): void
    { if(!in_array('sqlite',PDO::getAvailableDrivers(),true))self::markTestSkipped();$db=$this->database();$id=(new UserService($db))->create('ownerdelete','Owner','long-enough-password','user','en_US','owner@example.com');$db->exec("INSERT INTO packs (id,name,slug,version_id,summary,game_version,loader,loader_version,index_json,created_at,updated_at) VALUES ('p','P','p','1','','1.20.1','fabric','1','{}','now','now')");$db->prepare("INSERT INTO pack_owners (pack_id,user_id,created_at) VALUES ('p',?,'now')")->execute([$id]);$this->expectException(\InvalidArgumentException::class);(new UserDeletionService($db))->delete($id,'DELETE USER'); }
    public function testDeletionRemovesIdentityAndAnonymizesHistory(): void
    { if(!in_array('sqlite',PDO::getAvailableDrivers(),true))self::markTestSkipped();$db=$this->database();$users=new UserService($db);$admin=$users->create('keepadmin','Keep','long-enough-password','admin','en_US','keep@example.com');$id=$users->create('deleteperson','Delete Person','long-enough-password','user','en_US','delete@example.com');$db->prepare('INSERT INTO audit_log (id,action,context,created_at) VALUES (?,?,?,?)')->execute([Database::id(),'pack.changed',json_encode(['actor_user_id'=>$id,'email'=>'delete@example.com','display_name'=>'Delete Person','pack_id'=>'safe']),Database::now()]);$db->prepare('INSERT INTO security_events (id,user_id,event_type,severity,context,created_at) VALUES (?,?,?,?,?,?)')->execute([Database::id(),$id,'login.failed','warning',json_encode(['username'=>'deleteperson','reason'=>'failed']),Database::now()]);$db->exec("INSERT INTO packs (id,name,slug,version_id,summary,game_version,loader,loader_version,index_json,created_at,updated_at) VALUES ('history-pack','P','history-pack','1','','1.20.1','fabric','1','{}','now','now')");$db->prepare('INSERT INTO pack_activity (id,pack_id,actor_user_id,action,result,summary,context,created_at) VALUES (?,?,?,?,?,?,?,?)')->execute([Database::id(),'history-pack',$id,'pack.changed','success','Delete Person changed metadata',json_encode(['display_name'=>'Delete Person','pack_id'=>'history-pack']),Database::now()]);$announcement=(new \Modright\AnnouncementService($db))->save(['severity'=>'info','audience'=>'user:'.$id,'title_en'=>'Private','message_en'=>'Targeted']);(new UserDeletionService($db))->delete($id,'DELETE USER');$stmt=$db->prepare('SELECT COUNT(*) FROM users WHERE id=?');$stmt->execute([$id]);self::assertSame(0,(int)$stmt->fetchColumn());self::assertSame('Deleted User',$users->find(UserDeletionService::DELETED_USER_ID)['display_name']);self::assertSame(UserDeletionService::DELETED_USER_ID,$db->query("SELECT user_id FROM security_events WHERE event_type='login.failed'")->fetchColumn());$context=json_decode($db->query("SELECT context FROM audit_log WHERE action='pack.changed'")->fetchColumn(),true);self::assertSame(UserDeletionService::DELETED_USER_ID,$context['actor_user_id']);self::assertSame('[deleted]',$context['email']);self::assertSame('safe',$context['pack_id']);$security=json_decode($db->query("SELECT context FROM security_events WHERE event_type='login.failed'")->fetchColumn(),true);self::assertSame('[deleted]',$security['username']);self::assertSame('failed',$security['reason']);$activityRow=$db->query("SELECT summary,context FROM pack_activity WHERE pack_id='history-pack'")->fetch();$activity=json_decode($activityRow['context'],true);self::assertSame('[deleted]',$activity['display_name']);self::assertSame('history-pack',$activity['pack_id']);self::assertSame('Deleted User changed metadata',$activityRow['summary']);$storedAnnouncement=(new \Modright\AnnouncementService($db))->find($announcement);self::assertSame('user:'.UserDeletionService::DELETED_USER_ID,$storedAnnouncement['audience']);self::assertNotNull($storedAnnouncement['archived_at']);self::assertNotSame('',$admin); }
}
